export function getCurrentPageData(data, index) {
  const DATA_LIMIT = 20;

  if (data.length === 0) return new Array(DATA_LIMIT).fill(0);

  const startIndex = (index - 1) * DATA_LIMIT;
  const endIndex = index * DATA_LIMIT;
  const currentPageData = data.slice(startIndex, endIndex);

  return currentPageData;
}

export const shuffleArray = (array) => {
  const copyArr = [...array];

  for (let i = copyArr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    const temp = copyArr[i];
    copyArr[i] = copyArr[j];
    copyArr[j] = temp;
  }
  return copyArr;
};
