import { Link } from "@react-navigation/native";
import React from "react";
import { FlatList } from "react-native";
import { View } from "react-native-web";
import useBooks from "~/utils/hooks/useBooks";
import useBurmese from "~/utils/hooks/useBurmese";

export default function TitleList() {
  const { data } = useBooks();

  const renderItem = React.useCallback(
    ({ item, index }) => <PostTitle title={item} index={index + 1} />,
    []
  );

  const modifyData = React.useMemo(() => data.map((e) => e.title), [data]);

  const keyExtractor = React.useCallback((_, index) => index.toString(), []);

  return (
    <View style={{ flex: 1, padding: 8 }}>
      <MenuTitle />
      <FlatList
        data={modifyData}
        renderItem={renderItem}
        keyExtractor={keyExtractor}
      />
    </View>
  );
}

const MenuTitle = () => {
  const text = useBurmese("ေခါင္းစဥ္ အားလံုး");

  return <div className="nav-brand fw-bold mb-3 text-light">{text}</div>;
};

class PostTitle extends React.PureComponent {
  render() {
    return <Title title={this.props.title} index={this.props.index} />;
  }
}

const Title = ({ title, index }) => {
  const mmTitle = useBurmese(title);

  return (
    <Link to={{ screen: "Post", params: { title: title } }}>
      <div className="text-decoration-none text-left text-light p-2">
        {index}. {mmTitle}
      </div>
    </Link>
  );
};
