import React from "react";
import useStorage from "./useStorage";

// Handling Context
const settingsContext = React.createContext();

export default function useSettings() {
  return React.useContext(settingsContext);
}

// Handling Provider
const initialSettings = {
  dark: true,
  font: "zawgyi",
  loading: true,
};

export function SettingsContextProvider({ children }) {
  const [settings, setSettings] = React.useState(initialSettings);
  const { setItem, getItem } = useStorage("@settings");

  // Read From Storage
  const readFromStorage = React.useCallback(() => {
    const item = getItem();
    item
      ? setSettings({ ...item, loading: false })
      : setSettings((prev) => ({ ...prev, loading: false }));
  }, []);

  React.useEffect(() => {
    readFromStorage();
  }, []);

  // Write To Storage
  const writeToStorage = React.useCallback((data) => {
    const copyData = { ...data };
    delete copyData.loading;
    setItem(data);
  });
  React.useEffect(() => {
    !settings.loading && writeToStorage(settings);
  }, [settings]);

  // Methods
  const changeTheme = React.useCallback(() => {
    setSettings((prev) => ({ ...prev, dark: !prev.dark }));
  }, []);

  const changeFont = React.useCallback(() => {
    setSettings((prev) => ({
      ...prev,
      font: prev.font === "zawgyi" ? "unicode" : "zawgyi",
    }));
  }, []);

  const value = {
    dark: settings.dark,
    font: settings.font,
    loading: settings.loading,
    changeTheme,
    changeFont,
  };

  return (
    <settingsContext.Provider value={value}>
      {children}
    </settingsContext.Provider>
  );
}
